mapper.select:
SELECT m.message_id, m.message, m.project, m.from_user_id, m.message_type, m.ref_id, m.`to`, m.is_read, m.create_time, CASE WHEN m.from_user_id = 0 THEN 'system' ELSE u.username END AS from_username, CASE WHEN m.from_user_id = 0 THEN '系统通知' ELSE u.nickname END AS from_nickname, CASE WHEN m.from_user_id = 0 THEN NULL ELSE u.avatar_url END AS from_avatar_url FROM tb_messages m LEFT JOIN tb_user u ON m.from_user_id = u.user_id AND m.from_user_id > 0 WHERE m.message_type = 'system' AND m.`to` = #{userId} AND m.is_delete_by_receiver = 0
AND m.project = #{project}
AND m.is_read = #{isRead}
ORDER BY m.create_time DESC

